import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster, toast } from 'react-hot-toast';
import { AppProvider, useAppContext } from './context/AppContext';

// Pages
import DashboardPage from './pages/DashboardPage';
import DocumentsPage from './pages/DocumentsPage';
import ConversationsPage from './pages/ConversationsPage';
import LeadsPage from './pages/LeadsPage';
import SettingsPage from './pages/SettingsPage';
import LoginPage from './pages/LoginPage';

// Components
import Sidebar from './components/Common/Sidebar';
import Header from './components/Common/Header';

// Services
import websocketService from './services/websocket';

// Styles
import './styles/global.css';

const AppContent = () => {
  const { user, loading } = useAppContext();
  const [wsStatus, setWsStatus] = useState('disconnected');

  useEffect(() => {
    // Connect WebSocket when user is authenticated
    if (user) {
      try {
        const token = localStorage.getItem('token');
        if (token) {
          // Connect WebSocket
          websocketService.connect(token);
          
          // ===== CONNECTION STATUS LISTENERS =====
          websocketService.on('connected', () => {
            console.log('✅ WebSocket connected');
            setWsStatus('connected');
            toast.success('🔌 Real-time connection established', { duration: 3000 });
          });

          websocketService.on('disconnected', (data) => {
            console.log('🔌 WebSocket disconnected:', data?.reason || 'Unknown reason');
            setWsStatus('disconnected');
            toast.error('📡 Connection lost. Reconnecting...', { duration: 3000 });
          });

          websocketService.on('reconnected', (data) => {
            console.log(`🔄 WebSocket reconnected after ${data?.attemptNumber || 'unknown'} attempts`);
            setWsStatus('connected');
            toast.success('✅ Connection restored', { duration: 3000 });
          });

          websocketService.on('reconnecting', (data) => {
            console.log(`🔄 Reconnecting... Attempt ${data?.attemptNumber || 'unknown'}`);
            toast.loading(`Reconnecting... (${data?.attemptNumber || 0}/${websocketService.maxReconnectAttempts || 10})`, {
              duration: 2000,
            });
          });

          websocketService.on('connect_error', (error) => {
            console.error('❌ WebSocket connection error:', error);
            setWsStatus('error');
            toast.error(`⚠️ Connection error: ${error?.message || 'Unknown error'}`, { duration: 5000 });
          });

          // ===== NOTIFICATION LISTENERS =====
          websocketService.on('notification', (data) => {
            console.log('🔔 Notification received:', data);
            toast.success(data.message || '🔔 New notification!', {
              duration: 4000,
              icon: '🔔',
            });
          });

          // ===== NEW LEAD LISTENER =====
          websocketService.on('new-lead', (data) => {
            console.log('👤 New lead captured:', data);
            toast.success(`🎉 New lead: ${data.name || 'Unknown'} from ${data.platform || 'Unknown platform'}`, {
              duration: 6000,
              icon: '🎉',
            });
          });

          // ===== CONVERSATION ESCALATED LISTENER =====
          websocketService.on('conversation-escalated', (data) => {
            console.log('⚠️ Conversation escalated:', data);
            toast.warning(`⚠️ Conversation escalated: ${data.reason || 'Complex issue'}`, {
              duration: 5000,
              icon: '⚠️',
            });
          });

          // ===== NEW MESSAGE LISTENER =====
          websocketService.on('message-received', (data) => {
            console.log('📩 New message received:', data);
            const sender = data.sender === 'assistant' ? 'AI Assistant' : data.sender || 'Customer';
            toast.info(`💬 New message from ${sender}`, {
              duration: 3000,
              icon: '💬',
            });
          });

          // ===== USER TYPING LISTENER =====
          websocketService.on('user-typing', (data) => {
            console.log('✏️ User typing:', data);
            if (data.isTyping) {
              toast.loading('User is typing...', { 
                id: 'typing-indicator',
                duration: 3000,
              });
            } else {
              toast.dismiss('typing-indicator');
            }
          });

          // ===== CONVERSATION UPDATES =====
          websocketService.on('conversation-updated', (data) => {
            console.log('🔄 Conversation updated:', data);
            toast.info(`🔄 Conversation ${data.conversationId || 'updated'}`, {
              duration: 3000,
              icon: '🔄',
            });
          });

          // ===== LEAD UPDATES =====
          websocketService.on('lead-updated', (data) => {
            console.log('📝 Lead updated:', data);
            toast.success(`📝 Lead updated: ${data.name || 'Unknown'}`, {
              duration: 3000,
              icon: '📝',
            });
          });

          // ===== SYSTEM STATUS =====
          websocketService.on('status', (data) => {
            console.log('📊 System status:', data);
            if (data.status === 'maintenance') {
              toast.warning('🛠️ System is undergoing maintenance. Some features may be unavailable.', {
                duration: 10000,
                icon: '🛠️',
              });
            }
          });
        }
      } catch (error) {
        console.error('WebSocket setup error:', error);
        toast.error('Failed to establish real-time connection', { duration: 5000 });
      }
    } else {
      // Clean up if user logs out
      if (websocketService.isConnected) {
        websocketService.disconnect();
        setWsStatus('disconnected');
      }
    }

    // Cleanup on unmount or when user changes
    return () => {
      try {
        // Remove all listeners
        websocketService.removeAllListeners();
        // Disconnect WebSocket
        websocketService.disconnect();
        setWsStatus('disconnected');
      } catch (error) {
        console.error('WebSocket cleanup error:', error);
      }
    };
  }, [user]);

  // Show connection status indicator
  const ConnectionStatus = () => (
    <div className={`connection-status ${wsStatus}`}>
      <span className={`status-dot ${wsStatus}`}></span>
      <span className="status-text">
        {wsStatus === 'connected' ? 'Connected' : 
         wsStatus === 'reconnecting' ? 'Reconnecting...' : 
         wsStatus === 'error' ? 'Connection Error' : 'Disconnected'}
      </span>
    </div>
  );

  if (loading) {
    return (
      <div className="loading-screen">
        <div className="loader">Loading...</div>
      </div>
    );
  }

  return (
    <Router>
      <div className="app">
        <Toaster 
          position="top-right"
          toastOptions={{
            duration: 4000,
            style: {
              background: '#363636',
              color: '#fff',
              borderRadius: '8px',
              padding: '12px 16px',
            },
            success: {
              duration: 3000,
              iconTheme: {
                primary: '#10B981',
                secondary: '#fff',
              },
            },
            error: {
              duration: 4000,
              iconTheme: {
                primary: '#EF4444',
                secondary: '#fff',
              },
            },
            warning: {
              duration: 4000,
              iconTheme: {
                primary: '#F59E0B',
                secondary: '#fff',
              },
            },
            loading: {
              duration: 2000,
              iconTheme: {
                primary: '#4F46E5',
                secondary: '#fff',
              },
            },
          }}
        />
        {user ? (
          <div className="app-layout">
            <Sidebar />
            <div className="main-content">
              <Header />
              <div className="page-content">
                <ConnectionStatus />
                <Routes>
                  <Route path="/" element={<Navigate to="/dashboard" />} />
                  <Route path="/dashboard" element={<DashboardPage />} />
                  <Route path="/documents" element={<DocumentsPage />} />
                  <Route path="/conversations" element={<ConversationsPage />} />
                  <Route path="/leads" element={<LeadsPage />} />
                  <Route path="/settings" element={<SettingsPage />} />
                  <Route path="/login" element={<Navigate to="/dashboard" />} />
                </Routes>
              </div>
            </div>
          </div>
        ) : (
          <Routes>
            <Route path="/login" element={<LoginPage />} />
            <Route path="*" element={<Navigate to="/login" />} />
          </Routes>
        )}
      </div>
    </Router>
  );
};

function App() {
  return (
    <AppProvider>
      <AppContent />
    </AppProvider>
  );
}

export default App;










